// HELPER: BARISTA COUNTER
// ============================================================
function buildBarCounter(x, gly, M) {
    const cg = new THREE.Group();
    cg.position.set(x, gly, -1.8);

    // Main wood counter body (slatted front)
    const counterBase = new THREE.Mesh(new THREE.BoxGeometry(5, 2.8, 1.2), M.cafeWood);
    counterBase.position.y = 1.4;
    cg.add(counterBase);
    // Slats
    for (let i = -4; i <= 4; i++) {
        const slat = new THREE.Mesh(new THREE.BoxGeometry(0.12, 2.8, 0.03), new THREE.MeshLambertMaterial({color: 0xb08040}));
        slat.position.set(i * 0.54, 1.4, 0.615);
        cg.add(slat);
    }
    // Marble top
    const marbleTop = new THREE.Mesh(new THREE.BoxGeometry(5.2, 0.1, 1.3), M.cafeMarble);
    marbleTop.position.y = 2.85;
    cg.add(marbleTop);

    // Glass display case on counter
    const glassCase = new THREE.Mesh(new THREE.BoxGeometry(2.5, 1.0, 0.8), new THREE.MeshBasicMaterial({color: 0xc8e8f4, transparent:true, opacity:0.3}));
    glassCase.position.set(0.5, 3.4, 0.1);
    cg.add(glassCase);
    // Case frame
    const caseFrame = new THREE.Mesh(new THREE.BoxGeometry(2.55, 0.06, 0.85), M.cafeDark);
    caseFrame.position.set(0.5, 3.93, 0.1);
    cg.add(caseFrame);
    // Pastries
    const bunMat = new THREE.MeshLambertMaterial({ color: 0xe2b878 });
    for (let bi = -1; bi <= 1; bi++) {
        const bun = new THREE.Mesh(new THREE.SphereGeometry(0.14, 8, 8), bunMat);
        bun.scale.y = 0.6;
        bun.position.set(0.5 + bi * 0.7, 2.96, 0.05);
        cg.add(bun);
    }

    // Espresso machine
    const espMachine = new THREE.Mesh(new THREE.BoxGeometry(0.8, 0.7, 0.6), M.cafeDark);
    espMachine.position.set(-1.3, 3.35, 0.05);
    cg.add(espMachine);
    const espGroup = new THREE.Mesh(new THREE.CylinderGeometry(0.1, 0.1, 0.22, 8), new THREE.MeshLambertMaterial({color: 0x888888}));
    espGroup.position.set(-1.3, 2.85, 0.2);
    cg.add(espGroup);
    const espLight = new THREE.Mesh(new THREE.SphereGeometry(0.045, 6, 6), new THREE.MeshBasicMaterial({color: 0x22c55e}));
    espLight.position.set(-1.55, 3.65, 0.2);
    cg.add(espLight);

    // Back shelving with bottles/canisters
    const shelf1 = new THREE.Mesh(new THREE.BoxGeometry(5, 0.08, 0.4), M.cafeWood);
    shelf1.position.set(0, 4.5, -0.55);
    cg.add(shelf1);
    const shelf2 = new THREE.Mesh(new THREE.BoxGeometry(5, 0.08, 0.4), M.cafeWood);
    shelf2.position.set(0, 5.5, -0.55);
    cg.add(shelf2);
    const jarMat = new THREE.MeshLambertMaterial({ color: 0x8fbccc });
    const jarMat2 = new THREE.MeshLambertMaterial({ color: 0xd4956a });
    for (let ji = -4; ji <= 4; ji += 1.1) {
        const jar = new THREE.Mesh(new THREE.CylinderGeometry(0.08, 0.07, 0.35, 8), ji%2===0 ? jarMat : jarMat2);
        jar.position.set(ji * 0.52, 4.72, -0.42);
        cg.add(jar);
    }

    // Barista figure (simple) 
    const baristaBody = new THREE.Mesh(new THREE.CylinderGeometry(0.25, 0.22, 1.4, 8), new THREE.MeshLambertMaterial({color: 0x1e293b}));
    baristaBody.position.set(-2.0, 0.7, 0.3);
    cg.add(baristaBody);
    const baristaHead = new THREE.Mesh(new THREE.SphereGeometry(0.2, 10, 10), new THREE.MeshLambertMaterial({color: 0xd4a574}));
    baristaHead.position.set(-2.0, 1.6, 0.3);
    cg.add(baristaHead);

    threeScene.add(cg);
}

