// HELPER: CHALKBOARD
// ============================================================
function buildChalkboard(x, y, z, M) {
    const cg = new THREE.Group();
    cg.position.set(x, y, z);
    // Frame
    const frameMat = new THREE.MeshLambertMaterial({color: 0x6b4a2a});
    const fT = new THREE.Mesh(new THREE.BoxGeometry(1.8, 0.1, 0.06), frameMat);
    fT.position.y = 0.7; cg.add(fT);
    const fB = new THREE.Mesh(new THREE.BoxGeometry(1.8, 0.1, 0.06), frameMat);
    fB.position.y = -0.7; cg.add(fB);
    const fL = new THREE.Mesh(new THREE.BoxGeometry(0.1, 1.5, 0.06), frameMat);
    fL.position.x = -0.9; cg.add(fL);
    const fR = new THREE.Mesh(new THREE.BoxGeometry(0.1, 1.5, 0.06), frameMat);
    fR.position.x = 0.9; cg.add(fR);
    // Board
    const board = new THREE.Mesh(new THREE.BoxGeometry(1.65, 1.38, 0.03), new THREE.MeshLambertMaterial({color: 0x1f2937}));
    board.position.z = -0.01;
    cg.add(board);
    // Chalk lines (menu items)
    const chkMat = new THREE.MeshBasicMaterial({color: 0xf0f0e8});
    [[0, 0.48, 0.82], [0, 0.28, 0.68], [0, 0.08, 0.74], [0, -0.12, 0.6], [0, -0.32, 0.78], [0, -0.52, 0.5]].forEach(p => {
        const line = new THREE.Mesh(new THREE.BoxGeometry(p[2], 0.04, 0.005), chkMat);
        line.position.set(p[0], p[1], 0.02); cg.add(line);
    });
    // Title chalk line (thicker)
    const title = new THREE.Mesh(new THREE.BoxGeometry(1.2, 0.06, 0.005), chkMat);
    title.position.set(0, 0.58, 0.02); cg.add(title);
    threeScene.add(cg);
}

// ============================================================
// HELPER: CAFE TABLE
// ============================================================
function buildCafeTable(x, gly, z, M) {
    const tg = new THREE.Group();
    tg.position.set(x, gly, z);
    // Single center leg
    const leg = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.06, 2.2), M.cafeDark);
    leg.position.y = 1.1;
    tg.add(leg);
    const legBase = new THREE.Mesh(new THREE.CylinderGeometry(0.4, 0.4, 0.06, 10), M.cafeDark);
    legBase.position.y = 0.03;
    tg.add(legBase);
    // Table top (wood)
    const top = new THREE.Mesh(new THREE.BoxGeometry(1.5, 0.1, 1.5), M.cafeWood);
    top.position.y = 2.2;
    tg.add(top);
    // Small plant on table
    const tPot = new THREE.Mesh(new THREE.CylinderGeometry(0.1, 0.07, 0.15, 8), new THREE.MeshLambertMaterial({color: 0xd0c8c0}));
    tPot.position.set(0, 2.32, 0);
    tg.add(tPot);
    const tPlant = new THREE.Mesh(new THREE.SphereGeometry(0.12, 8, 8), M.cafePlant);
    tPlant.position.set(0, 2.5, 0);
    tg.add(tPlant);

    // 2 chairs
    for (let s = 0; s < 2; s++) {
        const angle = s * Math.PI;
        const cx = Math.sin(angle) * 1.1;
        const cz = Math.cos(angle) * 1.1;
        buildCafeChair(tg, cx, 0, cz, angle + Math.PI, M);
    }

    threeScene.add(tg);
}

function buildCafeChair(parent, cx, cy, cz, ry, M) {
    const cg = new THREE.Group();
    cg.position.set(cx, cy, cz);
    cg.rotation.y = ry;
    // Seat pad
    const seat = new THREE.Mesh(new THREE.BoxGeometry(0.9, 0.1, 0.9), M.cafeChair);
    seat.position.y = 1.1;
    cg.add(seat);
    // 4 legs
    for (let lx of [-0.35, 0.35]) for (let lz of [-0.35, 0.35]) {
        const l = new THREE.Mesh(new THREE.CylinderGeometry(0.04, 0.03, 1.1), M.cafeWood);
        l.position.set(lx, 0.55, lz);
        cg.add(l);
    }
    // Back rest
    const back = new THREE.Mesh(new THREE.BoxGeometry(0.9, 0.7, 0.06), M.cafeChair);
    back.position.set(0, 1.65, -0.45);
    cg.add(back);
    // Back legs extension
    for (let lx of [-0.35, 0.35]) {
        const bl = new THREE.Mesh(new THREE.CylinderGeometry(0.04, 0.03, 0.7), M.cafeWood);
        bl.position.set(lx, 1.45, -0.45);
        cg.add(bl);
    }
    parent.add(cg);
}

