// =================== SPRITE CHARACTERS ===================
function buildSpriteCharacters() {
    p1Mesh = makeSpriteCharacter(p1Char, -2.5);
    p2Mesh = makeSpriteCharacter(p2Char, 2.5);
    threeScene.add(p1Mesh);
    threeScene.add(p2Mesh);
}

function makeSpriteCharacter(charKey, xPos) {
    const def = CHAR_DEFS[charKey];
    const dataURL = window.__SPRITE_ATLASES[def.atlas];
    const loader = new THREE.TextureLoader();
    const tex = loader.load(dataURL, (loadedTex) => {
        // Once loaded, set proper repeat and offset
        loadedTex.repeat.set(1/ATLAS_FRAMES, 1);
        loadedTex.offset.set(0, 0);
        loadedTex.needsUpdate = true;
    });
    tex.magFilter = THREE.NearestFilter;
    tex.minFilter = THREE.NearestFilter;
    tex.wrapS = THREE.ClampToEdgeWrapping;
    tex.wrapT = THREE.ClampToEdgeWrapping;
    // Try both SRGBColorSpace (newer) and sRGBEncoding (older r128)
    if (THREE.SRGBColorSpace !== undefined) tex.colorSpace = THREE.SRGBColorSpace;
    else if (THREE.sRGBEncoding !== undefined) tex.encoding = THREE.sRGBEncoding;

    // Set initial frame
    tex.repeat.set(1/ATLAS_FRAMES, 1);
    tex.offset.set(0, 0);

    const mat = new THREE.MeshBasicMaterial({
        map: tex,
        transparent: true,
        alphaTest: 0.15,  // Reduced from 0.3 to show more of the sprite
        side: THREE.DoubleSide,
        depthWrite: false
    });

    const W = 2.2, H = 3.3;  // Larger billboard for higher-res character appearance
    const geom = new THREE.PlaneGeometry(W, H);
    const mesh = new THREE.Mesh(geom, mat);
    mesh.position.set(xPos, groundLevelY + H/2, 0);
    mesh.userData = {
        atlasTex: tex,
        currentFrame: -1,  // Force update on first call
        facing: 0,          // Force update on first call
        baseY: groundLevelY + H/2,
        H: H, W: W
    };
    return mesh;
}

function setMeshFrame(mesh, frameIdx, facing) {
    const ud = mesh.userData;
    // Only update if something changed (avoid redundant GPU texture uploads)
    if (ud.currentFrame === frameIdx && ud.facing === (facing === undefined ? ud.facing : facing)) return;
    ud.currentFrame = frameIdx;
    if (facing === undefined) facing = ud.facing;
    ud.facing = facing;

    // Inset by 1px from each edge to prevent UV bleeding between atlas frames.
    // Use actual image width when available, fall back to 192px-per-frame estimate.
    const texW = (ud.atlasTex.image && ud.atlasTex.image.width) ? ud.atlasTex.image.width : (ATLAS_FRAMES * 192);
    const inset = 1.0 / texW;
    ud.atlasTex.repeat.x = (1 / ATLAS_FRAMES) - 2 * inset;
    ud.atlasTex.offset.x = (frameIdx / ATLAS_FRAMES) + inset;
    ud.atlasTex.needsUpdate = true;

    // Flip the mesh horizontally instead of the UV
    mesh.scale.x = (facing === 1) ? Math.abs(mesh.scale.x) : -Math.abs(mesh.scale.x);
}

// =================== PARTICLES ===================
// ===== VFX SPRITE SYSTEM =====
// Uses the VFX smoke atlas for hit effects
let vfxSprites = [];
let vfxTexture = null;

function initVFXTexture() {
    if (!threeScene || !VFX_SMOKE_ATLAS) return;
    const loader = new THREE.TextureLoader();
    vfxTexture = loader.load(VFX_SMOKE_ATLAS);
    vfxTexture.magFilter = THREE.LinearFilter;
    vfxTexture.minFilter = THREE.LinearFilter;
}

function spawnHitVFX(worldX, worldY, type) {
    if (!threeScene || !vfxTexture) return;
    // Spawn a hit flash + dust puff using VFX texture
    // Create a billboard quad with VFX texture
    const size = type === 'special' ? 1.8 : (type === 'kick' ? 1.2 : 0.9);
    const geo = new THREE.PlaneGeometry(size, size);
    const mat = new THREE.MeshBasicMaterial({ 
        map: vfxTexture, 
        transparent: true, 
        alphaTest: 0.05,
        side: THREE.DoubleSide,
        depthWrite: false,
        blending: THREE.AdditiveBlending
    });
    // Use a specific region of the VFX texture (white cloud, top-center area)
    // VFX atlas is 716x709 - use the white puff clouds
    mat.map.repeat.set(0.25, 0.25);
    mat.map.offset.set(0.35, 0.6); // white cloud region
    
    const mesh = new THREE.Mesh(geo, mat);
    mesh.position.set(worldX, worldY + 0.3, 0.6);
    mesh.rotation.z = Math.random() * Math.PI;
    threeScene.add(mesh);
    
    const life = type === 'special' ? 0.45 : 0.28;
    vfxSprites.push({ mesh, geo, mat, life, maxLife: life, type });
    
    // Also spawn colored hit flash
    const flashGeo = new THREE.PlaneGeometry(size * 0.7, size * 0.7);
    const color = type === 'special' ? 0xffaa00 : (type === 'kick' ? 0x44aaff : 0xffffff);
    const flashMat = new THREE.MeshBasicMaterial({ 
        color, transparent: true, opacity: 0.9, 
        blending: THREE.AdditiveBlending, depthWrite: false 
    });
    const flashMesh = new THREE.Mesh(flashGeo, flashMat);
    flashMesh.position.set(worldX, worldY + 0.3, 0.7);
    threeScene.add(flashMesh);
    vfxSprites.push({ mesh: flashMesh, geo: flashGeo, mat: flashMat, life: 0.1, maxLife: 0.1, type: 'flash' });
}

function spawnDustVFX(worldX, worldY) {
    if (!threeScene) return;
    // Small dust puff for footsteps/landing
    for (let i = 0; i < 3; i++) {
        const geo = new THREE.PlaneGeometry(0.3, 0.3);
        const mat = new THREE.MeshBasicMaterial({ 
            color: 0xd4b896, transparent: true, opacity: 0.7,
            blending: THREE.NormalBlending, depthWrite: false
        });
        const mesh = new THREE.Mesh(geo, mat);
        const ox = (Math.random() - 0.5) * 0.6;
        mesh.position.set(worldX + ox, worldY + 0.05, 0.2);
        threeScene.add(mesh);
        const vel = { x: (Math.random()-0.5)*1.5, y: 0.8+Math.random()*0.8 };
        vfxSprites.push({ mesh, geo, mat, life: 0.6, maxLife: 0.6, type: 'dust', vel });
    }
}

function updateVFXSprites(dt) {
    for (let i = vfxSprites.length - 1; i >= 0; i--) {
        const vfx = vfxSprites[i];
        vfx.life -= dt;
        const t = vfx.life / vfx.maxLife; // 1->0
        
        if (vfx.type === 'flash') {
            vfx.mat.opacity = t * 0.9;
            const s = 1.0 + (1.0 - t) * 1.5;
            vfx.mesh.scale.set(s, s, 1);
        } else if (vfx.type === 'dust' && vfx.vel) {
            vfx.mesh.position.x += vfx.vel.x * dt;
            vfx.mesh.position.y += vfx.vel.y * dt;
            vfx.vel.y -= 3.0 * dt;
            vfx.mat.opacity = t * 0.7;
            vfx.mesh.scale.set(1 + (1-t)*0.5, 1 + (1-t)*0.5, 1);
        } else {
            // Smoke puff: expand and fade
            const s = 1.0 + (1.0 - t) * 2.0;
            vfx.mesh.scale.set(s, s, 1);
            vfx.mat.opacity = t * 0.8;
            vfx.mesh.position.y += 0.6 * dt;
            vfx.mesh.rotation.z += 1.5 * dt;
        }
        
        if (vfx.life <= 0) {
            threeScene.remove(vfx.mesh);
            vfx.geo.dispose();
            vfx.mat.dispose();
            vfxSprites.splice(i, 1);
        }
    }
}

function spawn3DParticle(pos, vel, color, size, duration) {
    if (!threeScene) return;
    const geo = new THREE.BoxGeometry(size, size, size);
    const mat = new THREE.MeshBasicMaterial({ color });
    const mesh = new THREE.Mesh(geo, mat);
    mesh.position.copy(pos);
    threeScene.add(mesh);
    particles.push({ mesh, geo, mat, velocity: vel.clone(), life: duration, maxLife: duration });
}

function update3DParticles(dt) {
    for (let i = particles.length-1; i >= 0; i--) {
        const p = particles[i];
        p.life -= dt;
        p.mesh.position.x += p.velocity.x * dt;
        p.mesh.position.y += p.velocity.y * dt;
        p.mesh.position.z += p.velocity.z * dt;
        p.velocity.y -= 9.8 * dt;
        p.mesh.scale.setScalar(Math.max(0, p.life / p.maxLife));
        if (p.mesh.position.y < groundLevelY) {
            p.mesh.position.y = groundLevelY;
            p.velocity.y = -p.velocity.y * 0.4;
            p.velocity.x *= 0.6;
        }
        if (p.life <= 0) {
            threeScene.remove(p.mesh);
            // FIX: dispose to avoid memory leak
            p.geo.dispose();
            p.mat.dispose();
            particles.splice(i, 1);
        }
    }
}

function onWindowResize() {
    if (!threeCamera || !threeRenderer) return;
    const container = document.getElementById('three-container');
    threeCamera.aspect = container.clientWidth / container.clientHeight;
    threeCamera.updateProjectionMatrix();
    const dprScale = 0.5;
    threeRenderer.setSize(container.clientWidth*dprScale, container.clientHeight*dprScale, false);
    if (phaserGame && phaserGame.scale)
        phaserGame.scale.resize(container.clientWidth, container.clientHeight);
    checkScreenOrientation();
    // Don't reset camera position - let the tracking system handle it
}

// =================== PHASER PHYSICS ===================
function initPhaser() {
    const config = {
        type: Phaser.AUTO, width: 800, height: 450, parent: 'phaser-container',
        transparent: true,
        scale: { mode: Phaser.Scale.FIT, autoCenter: Phaser.Scale.CENTER_BOTH },
        physics: { default:'arcade', arcade: { gravity:{ y:1200 }, debug:false } },
        scene: { create: phaserCreate, update: phaserUpdate }
    };
    phaserGame = new Phaser.Game(config);
}

function phaserCreate() {
    const scene = this;
    const mapDef = MAP_DEFS[selectedMap] || MAP_DEFS.cafe;
    const mo = mapDef.phaserOffset; // map offset in Phaser coords
    // Extended world bounds for multi-environment scrolling stage
    scene.physics.world.setBounds(-3200, 0, 7200, 450);

    const rect1 = scene.add.rectangle(250 + mo, 350, 50, 100, 0x000000, 0);
    scene.physics.add.existing(rect1);
    player1State = {
        body: rect1, health: CHAR_DEFS[p1Char].hp, maxHealth: CHAR_DEFS[p1Char].hp,
        super: 20, combo: 0, state:'idle', facing:1, attackTimer:0, isBlocking:false,
        isDucking:false, hitstun:0, dieTimer:0, charKey: p1Char
    };
    player1State.body.body.setCollideWorldBounds(true);

    const rect2 = scene.add.rectangle(550 + mo, 350, 50, 100, 0x000000, 0);
    scene.physics.add.existing(rect2);
    player2State = {
        body: rect2, health: CHAR_DEFS[p2Char].hp, maxHealth: CHAR_DEFS[p2Char].hp,
        super: 20, combo: 0, state:'idle', facing:-1, attackTimer:0, isBlocking:false,
        isDucking:false, hitstun:0, dieTimer:0, charKey: p2Char
    };
    player2State.body.body.setCollideWorldBounds(true);

    const ground = scene.physics.add.staticGroup();
    // Ground spans the full extended world width
    ground.create(400, 430, null).setSize(14400, 40).setVisible(false);
    scene.physics.add.collider(player1State.body, ground);
    scene.physics.add.collider(player2State.body, ground);
    scene.physics.add.collider(player1State.body, player2State.body);

    scene.keys = {
        A: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.A),
        D: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.D),
        W: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.W),
        S: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.S),
        J: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.J),
        K: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.K),
        L: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.L),
        LEFT: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.LEFT),
        RIGHT: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.RIGHT),
        UP: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.UP),
        DOWN: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.DOWN),
        ONE: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.ONE),
        TWO: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.TWO),
        THREE: scene.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.THREE)
    };
    setupTouchEvents();
}

function bindTouchButton(elementIds, key) {
    elementIds.forEach(id => {
        const btn = document.getElementById(id);
        if (!btn) return;
        // Use pointer events for better cross-device support
        btn.style.touchAction = 'none';
        btn.style.userSelect = 'none';
        btn.style.webkitUserSelect = 'none';
        
        const onPress = (e) => { 
            if (e.cancelable) e.preventDefault(); 
            e.stopPropagation();
            window.touchInputs[key] = true; 
            btn.classList.add('active'); 
            // Capture pointer so subsequent events go to this button even if finger drifts
            if (e.pointerId !== undefined && btn.setPointerCapture) {
                try { btn.setPointerCapture(e.pointerId); } catch(err){}
            }
        };
        const onRelease = (e) => { 
            if (e && e.cancelable) e.preventDefault();
            window.touchInputs[key] = false; 
            btn.classList.remove('active'); 
        };
        
        // Pointer events (works for both touch and mouse)
        btn.addEventListener('pointerdown', onPress, { passive:false });
        btn.addEventListener('pointerup', onRelease, { passive:false });
        btn.addEventListener('pointercancel', onRelease, { passive:false });
        // NOTE: do NOT bind pointerleave - it fires when finger drifts and erroneously clears the button
    });
}

function createVirtualJoystick(baseId, thumbId) {
    const base = document.getElementById(baseId);
    const thumb = document.getElementById(thumbId);
    if (!base || !thumb) return;
    let isDragging=false, startX=0, startY=0, wasActive=false;
    const maxRadius = 35;
    const onStart = (cx, cy) => {
        isDragging = true;
        const rect = base.getBoundingClientRect();
        startX = rect.left + rect.width/2; startY = rect.top + rect.height/2;
        moveThumb(cx, cy);
    };
    const onMove = (cx, cy) => { if (isDragging) moveThumb(cx, cy); };
    const onEnd = () => {
        isDragging = false;
        thumb.style.left='50%'; thumb.style.top='50%';
        thumb.style.transform='translate(-50%, -50%)';
        // Only clear inputs that THIS joystick was setting (don't clobber other joystick)
        if (wasActive) {
            window.touchInputs.left=false; window.touchInputs.right=false;
            window.touchInputs.up=false; window.touchInputs.down=false;
        }
        wasActive = false;
    };
    const moveThumb = (cx, cy) => {
        let dx = cx-startX, dy = cy-startY;
        const dist = Math.sqrt(dx*dx + dy*dy);
        if (dist > maxRadius) { dx=(dx/dist)*maxRadius; dy=(dy/dist)*maxRadius; }
        thumb.style.transform='none';
        thumb.style.left = `${(dx + base.clientWidth/2) - thumb.clientWidth/2}px`;
        thumb.style.top = `${(dy + base.clientHeight/2) - thumb.clientHeight/2}px`;
        const dz = 12;
        const l = (dx < -dz), r = (dx > dz), u = (dy < -dz), d = (dy > dz);
        if (l||r||u||d) wasActive = true;
        window.touchInputs.left = l;
        window.touchInputs.right = r;
        window.touchInputs.up = u;
        window.touchInputs.down = d;
    };
    // Pointer events for joystick (works touch + mouse)
    base.addEventListener('pointerdown', (e) => { e.preventDefault(); base.setPointerCapture(e.pointerId); onStart(e.clientX, e.clientY); }, { passive:false });
    base.addEventListener('pointermove', (e) => { if (isDragging) { e.preventDefault(); onMove(e.clientX, e.clientY); } }, { passive:false });
    base.addEventListener('pointerup', (e) => { base.releasePointerCapture(e.pointerId); onEnd(); }, { passive:false });
    base.addEventListener('pointercancel', () => onEnd(), { passive:false });
    // Fallback
    base.addEventListener('touchstart', (e) => { e.preventDefault(); onStart(e.touches[0].clientX, e.touches[0].clientY); }, { passive:false });
    window.addEventListener('touchmove', (e) => { if (isDragging && e.cancelable) { e.preventDefault(); onMove(e.touches[0].clientX, e.touches[0].clientY); } }, { passive:false });
    window.addEventListener('touchend', onEnd, { passive:true });
}

function setupTouchEvents() {
    createVirtualJoystick('deck-joystick','deck-joystick-thumb');
    createVirtualJoystick('float-joystick','float-joystick-thumb');
    bindTouchButton(['btn-punch','float-punch'], 'punch');
    bindTouchButton(['btn-kick','float-kick'], 'kick');
    bindTouchButton(['btn-special','float-special'], 'special');
}

function phaserUpdate(time, delta) {
    if (!gameActive || gamePaused || !player1State || !player2State) return;
    const dt = delta/1000;
    const scene = this;

    if (player1State.attackTimer > 0) player1State.attackTimer -= dt;
    if (player2State.attackTimer > 0) player2State.attackTimer -= dt;
    if (player1State.hitstun > 0) player1State.hitstun -= dt;
    if (player2State.hitstun > 0) player2State.hitstun -= dt;

    if (player1State.body.x < player2State.body.x) {
        player1State.facing = 1; player2State.facing = -1;
    } else {
        player1State.facing = -1; player2State.facing = 1;
    }

    const isDown = (k) => k && k.isDown;
    const p1Spd = 200 * CHAR_DEFS[p1Char].speed;
    const p2Spd = 200 * CHAR_DEFS[p2Char].speed;

    // P1 INPUTS
    let p1VelX = 0;
    player1State.isBlocking = false;
    if (!player1State.dashTimer) player1State.dashTimer = 0;
    if (player1State.dashTimer > 0) player1State.dashTimer -= dt;
    if (player1State.hitstun <= 0) {
        // Dash detection: double-tap direction within devConfig window
        const _now = performance.now() / 1000;
        if (Phaser.Input.Keyboard.JustDown(scene.keys.D) || (window.touchInputs.right && !window._prevTouch?.right)) {
            const sm = devCheckSpecialInput('right');
            if (sm === 'dash') { player1State.dashTimer = 0.28; player1State.state='dashing'; }
            player1State._lastRightT = _now;
        }
        if (Phaser.Input.Keyboard.JustDown(scene.keys.A) || (window.touchInputs.left && !window._prevTouch?.left)) {
            const sm = devCheckSpecialInput('left');
            if (sm === 'dash') { player1State.dashTimer = 0.28; player1State.state='dashing'; }
            player1State._lastLeftT = _now;
        }
        window._prevTouch = Object.assign({}, window.touchInputs);

        const dashBoost = (player1State.dashTimer > 0) ? 2.3 : 1.0;
        if (isDown(scene.keys.A) || window.touchInputs.left) {
            p1VelX = -p1Spd * dashBoost;
            if (player1State.state !== 'dashing') player1State.state = 'walking';
        } else if (isDown(scene.keys.D) || window.touchInputs.right) {
            p1VelX = p1Spd * dashBoost;
            if (player1State.state !== 'dashing') player1State.state = 'walking';
        } else {
            if (player1State.dashTimer <= 0) player1State.state = 'idle';
        }
        if ((isDown(scene.keys.W) || window.touchInputs.up) && player1State.body.body.touching.down) {
            player1State.body.body.setVelocityY(-600);
            player1State._wasAirborne = true;
        }
        if (player1State._wasAirborne && player1State.body.body.touching.down) {
            player1State._wasAirborne = false;
            spawnDustVFX((player1State.body.x - 400) * 0.012, groundLevelY);
        }
        const p1Airborne = !player1State.body.body.touching.down;
        if (isDown(scene.keys.S) || window.touchInputs.down) {
            if (p1Airborne) {
                // Fast-fall while airborne — no duck state
            } else {
                player1State.isDucking = true;
                player1State.isBlocking = true;
                player1State.state = 'ducking';
                p1VelX = 0;
            }
        } else {
            player1State.isDucking = false;
        }
    }
    const p1Airborne = !player1State.body.body.touching.down;
    if (player1State.state==='punching' || player1State.state==='kicking' ||
        player1State.state==='special' || player1State.state==='jump_kicking' ||
        player1State.state==='duck_punching') {
        player1State.body.body.setVelocityX(0);
    } else if (player1State.hitstun <= 0) {
        player1State.body.body.setVelocityX(p1VelX);
    }

    if (player1State.hitstun <= 0 && player1State.attackTimer <= 0) {
        if (Phaser.Input.Keyboard.JustDown(scene.keys.J) || window.touchInputs.punch) {
            if (player1State.isDucking) triggerAttack('p1','duck_punch');
            else                        triggerAttack('p1','punch');
            window.touchInputs.punch = false;
        } else if (Phaser.Input.Keyboard.JustDown(scene.keys.K) || window.touchInputs.kick) {
            if (p1Airborne) triggerAttack('p1','jump_kick');
            else            triggerAttack('p1','kick');
            window.touchInputs.kick = false;
        } else if (Phaser.Input.Keyboard.JustDown(scene.keys.L) || window.touchInputs.special) {
            if (player1State.super >= 50) {
                triggerAttack('p1','special');
                player1State.super -= 50;
                updateHPUI();
            }
            window.touchInputs.special = false;
        }
    }

    // P2 INPUTS
    if (isPVPMode) {
        let p2VelX = 0;
        player2State.isBlocking = false;
        if (player2State.hitstun <= 0) {
            if (isDown(scene.keys.LEFT)) { p2VelX = -p2Spd; player2State.state='walking'; }
            else if (isDown(scene.keys.RIGHT)) { p2VelX = p2Spd; player2State.state='walking'; }
            else { player2State.state='idle'; }
            if (isDown(scene.keys.UP) && player2State.body.body.touching.down)
                player2State.body.body.setVelocityY(-600);
            if (isDown(scene.keys.DOWN)) { player2State.isBlocking=true; player2State.state='block'; p2VelX=0; }
        }
        if (player2State.state==='punching' || player2State.state==='kicking' || player2State.state==='special') {
            player2State.body.body.setVelocityX(0);
        } else if (player2State.hitstun <= 0) {
            player2State.body.body.setVelocityX(p2VelX);
        }
        if (player2State.hitstun <= 0 && player2State.attackTimer <= 0) {
            if (Phaser.Input.Keyboard.JustDown(scene.keys.ONE)) triggerAttack('p2','punch');
            else if (Phaser.Input.Keyboard.JustDown(scene.keys.TWO)) triggerAttack('p2','kick');
            else if (Phaser.Input.Keyboard.JustDown(scene.keys.THREE)) {
                if (player2State.super >= 50) {
                    triggerAttack('p2','special');
                    player2State.super -= 50;
                    updateHPUI();
                }
            }
        }
    } else {
        executeAI();
    }

    syncPhysicsToRender();
    // Update portraits based on current action state
    updatePortraits(dt);
}

// =================== ATTACK LOGIC ===================
function triggerAttack(attacker, type) {
    if (!gameActive) return;  // BUGFIX: don't process attacks after match end
    const state = attacker==='p1' ? player1State : player2State;
    const opponent = attacker==='p1' ? player2State : player1State;
    if (!state || !opponent) return;

    const stateMap = { punch:'punching', kick:'kicking', special:'special',
                       jump_kick:'jump_kicking', duck_punch:'duck_punching' };
    state.state = stateMap[type] || 'punching';
    const atkDur = type==='special' ? 0.6 : (type==='kick'||type==='jump_kick' ? 0.4 : 0.35);
    state.attackTimer = atkDur;
    state.attackDuration = atkDur;
    audio.playHit(type==='special' ? 'special' : (type==='kick'||type==='jump_kick' ? 'kick' : 'punch'));

    const dmgMod = CHAR_DEFS[state.charKey].dmg;
    const reach = type==='special' ? 140 : (type==='kick'||type==='jump_kick' ? 115 : (type==='duck_punch' ? 90 : 85));
    const dist = Math.abs(state.body.x - opponent.body.x);
    const inYRange = Math.abs(state.body.y - opponent.body.y) < (type==='jump_kick' ? 160 : 100);

    if (dist < reach && inYRange) {
        const blockActive = opponent.isBlocking && !opponent.isDucking && (
            (state.body.x < opponent.body.x && opponent.facing === -1) ||
            (state.body.x > opponent.body.x && opponent.facing === 1)
        );
        // Duck punch hits ducking opponents; jump kick hits standing opponents from above
        const duckBlocks = type === 'duck_punch' && opponent.isDucking;
        if (blockActive && !duckBlocks) {
            audio.playHit('punch');
            opponent.body.body.setVelocityX(state.facing * 100);
        } else {
            audio.playHit(type==='kick'||type==='jump_kick' ? 'kick' : 'punch');
            const baseDmg = type==='special' ? 25 : (type==='kick' ? 12 : type==='jump_kick' ? 15 : type==='duck_punch' ? 10 : 7);
            const dmg = Math.round(baseDmg * dmgMod);
            opponent.health = Math.max(0, opponent.health - dmg);
            state.super = Math.min(100, state.super + (type==='punch'||type==='duck_punch' ? 8 : 15));

            const knockX = type==='special' ? 650 : (type==='jump_kick' ? 500 : 350);
            const knockY = type==='special' ? -250 : (type==='jump_kick' ? -300 : -100);
            opponent.body.body.setVelocityX(state.facing * knockX);
            opponent.body.body.setVelocityY(knockY);
            opponent.hitstun = type==='special' ? 0.5 : (type==='jump_kick' ? 0.4 : 0.25);
            opponent.state = 'hit';

            triggerCameraShake();
            incrementCombo(attacker);

            // Hit VFX
            const hitWorldX = (opponent.body.x - 400) * 0.012;
            const hitWorldY = groundLevelY + 1.3;
            
            // Fancy VFX sprite effect
            spawnHitVFX(hitWorldX, hitWorldY, type);
            
            // Also spawn classic particles for extra juice
            const hitPos = new THREE.Vector3(hitWorldX, hitWorldY, 0.5);
            const numParts = type === 'special' ? 16 : (type === 'kick' ? 10 : 6);
            for (let j = 0; j < numParts; j++) {
                spawn3DParticle(
                    hitPos.clone(),
                    new THREE.Vector3(state.facing*(2+Math.random()*5), 2+Math.random()*5, (Math.random()-0.5)*2),
                    CHAR_DEFS[state.charKey].color, 0.07 + Math.random()*0.04, 0.5 + Math.random()*0.3
                );
            }
            updateHPUI();
            if (opponent.health <= 0) endMatch();
        }
    }

    // Hit breakables in range
    breakables.forEach(b => {
        if (!b.broken) {
            const phaserX = 400 + (b.x / 0.012);
            const propDist = Math.abs(state.body.x - phaserX);
            if (propDist < reach + 25) {
                b.health--;
                audio.playSpark();
                if (b.health <= 0) {
                    b.broken = true;
                    b.onBreak();
                }
            }
        }
    });
}

function incrementCombo(attacker) {
    const isP1 = attacker==='p1';
    const key = isP1 ? 'p1' : 'p2';
    comboSystem[key]++;
    const box = document.getElementById(key+'-combo-box');
    const cnt = document.getElementById(key+'-combo-count');
    if (cnt) cnt.innerText = comboSystem[key];
    if (box) {
        box.style.opacity = "1";
        box.style.transform = "translateX(0px)";
    }
    if (comboSystem[key+'Timer']) clearTimeout(comboSystem[key+'Timer']);
    comboSystem[key+'Timer'] = setTimeout(() => {
        if (box) {
            box.style.opacity = "0";
            box.style.transform = `translateX(${isP1 ? '-50px' : '50px'})`;
        }
        comboSystem[key] = 0;
    }, 1500);
}

function executeAI() {
    const ai = player2State, player = player1State;
    if (!ai || !player) return;
    // CRITICAL FIX: AI block duration with timer so it doesn't get stuck blocking forever
    ai.aiBlockTimer = (ai.aiBlockTimer || 0) - (1/60);
    ai.isBlocking = ai.aiBlockTimer > 0;
    if (ai.hitstun > 0 || ai.attackTimer > 0) return;
    const dist = Math.abs(ai.body.x - player.body.x);
    const r = Math.random();
    ai.facing = ai.body.x < player.body.x ? 1 : -1;
    const aiSpd = 140 * CHAR_DEFS[p2Char].speed;
    if (dist > 90) {
        ai.body.body.setVelocityX(ai.facing * aiSpd);
        ai.state = 'walking';
    } else {
        ai.body.body.setVelocityX(0);
        if (r < 0.18) triggerAttack('p2','punch');
        else if (r < 0.25) triggerAttack('p2','kick');
        else if (r < 0.35 && ai.super >= 50) {
            triggerAttack('p2','special'); ai.super -= 50; updateHPUI();
        } else if (r < 0.42) { ai.aiBlockTimer = 0.4; ai.isBlocking = true; ai.state = 'block'; }
        else ai.state = 'idle';
    }
}

// =================== SYNC PHYSICS -> RENDER ===================
function syncPhysicsToRender() {
    if (!p1Mesh || !p2Mesh || !player1State || !player2State) return;
    // Convert Phaser coord (800x450) to Three.js world coord
    const p1NewX = (player1State.body.x - 400) * 0.012;
    const p2NewX = (player2State.body.x - 400) * 0.012;
    
    // Track velocity for run detection
    player1State.velX = (p1NewX - p1Mesh.position.x) / 0.016;
    player2State.velX = (p2NewX - p2Mesh.position.x) / 0.016;
    
    p1Mesh.position.x = p1NewX;
    p2Mesh.position.x = p2NewX;
    p1Mesh.position.y = p1Mesh.userData.baseY + (-(player1State.body.y - 380) * 0.012);
    p2Mesh.position.y = p2Mesh.userData.baseY + (-(player2State.body.y - 380) * 0.012);

    const t = threeClock ? threeClock.getElapsedTime() : Date.now()*0.001;
    updateSpriteFrame(p1Mesh, player1State, t);
    updateSpriteFrame(p2Mesh, player2State, t);
}

function updateSpriteFrame(mesh, state, t) {
    const anim = (window.devConfig && window.devConfig.actionAnimMap) || {};
    const getF = (key, fallback) => (anim[key] && anim[key].length) ? anim[key] : fallback;
    const cycle = (frames, spd) => frames[Math.floor(t * spd) % frames.length];
    const progress = (frames, p) => frames[Math.min(Math.floor(p * frames.length), frames.length - 1)];

    let frame;
    const airborne = state.body && state.body.body && !state.body.body.touching.down;

    if (state.state === 'dying') {
        const f = getF('die', [FRAME_DIE_A, FRAME_DIE_B, FRAME_DIE_C]);
        frame = f[Math.min(Math.floor(state.dieTimer * 6), f.length - 1)];
    } else if (state.state === 'taunt' || state.state === 'win') {
        frame = cycle(getF('taunt', [FRAME_TAUNT_A, FRAME_TAUNT_B]), 4);
    } else if (state.hitstun > 0) {
        const hf = getF('hit', [FRAME_HIT]);
        frame = (Math.floor(state.hitstun * 20) % 2 === 0) ? hf[0] : FRAME_IDLE;
    } else if (state.isBlocking) {
        frame = getF('block', [FRAME_BLOCK])[0];
    } else if (state.isDucking) {
        frame = getF('duck', [FRAME_DUCK])[0];
    } else if (state.attackTimer > 0) {
        const p = 1.0 - (state.attackTimer / state.attackDuration);
        if (state.state === 'jump_kicking') {
            const f = getF('jump_kick', [FRAME_JKICK_A, FRAME_JKICK_B]);
            frame = progress(f, p);
        } else if (state.state === 'duck_punching') {
            const f = getF('duck_punch', [FRAME_DPUNCH_A, FRAME_DPUNCH_B]);
            frame = progress(f, p);
        } else if (state.state === 'punching') {
            frame = progress(getF('punch', [FRAME_PUNCH_A, FRAME_PUNCH_B, FRAME_PUNCH_C]), p);
        } else if (state.state === 'kicking') {
            frame = progress(getF('kick', [FRAME_KICK_A, FRAME_KICK_B, FRAME_KICK_C]), p);
        } else {
            frame = progress(getF('special', [FRAME_SPEC_A, FRAME_SPEC_B, FRAME_SPEC_C, FRAME_SPEC_D]), p);
        }
    } else if (state.dashTimer > 0) {
        frame = cycle(getF('dash', [FRAME_RUN_A, FRAME_RUN_B, FRAME_RUN_A]), 18);
    } else if (airborne) {
        const f = getF('jump', [FRAME_JUMP_A, FRAME_JUMP_B]);
        // Show rise frame going up, air frame coming down
        const vy = state.body.body.velocity.y;
        frame = vy < 0 ? f[0] : f[Math.min(1, f.length - 1)];
    } else if (state.state === 'running') {
        frame = cycle(getF('run', [FRAME_RUN_A, FRAME_RUN_B, FRAME_RUN_A]), 14);
    } else if (state.state === 'walking') {
        frame = cycle(getF('walk', [FRAME_WALK_A, FRAME_WALK_B, FRAME_WALK_C]), 9);
    } else {
        frame = getF('idle', [FRAME_IDLE])[0];
    }
    setMeshFrame(mesh, frame, state.facing);
}

// =================== HUD & PORTRAIT CYCLING ===================

// Portrait cycling state
let p1PortraitCanvas = null;
let p2PortraitCanvas = null;
let p1PortraitState = 'idle';  // 'idle' or 'action'
let p2PortraitState = 'idle';
let p1PortraitTimer = 0;
let p2PortraitTimer = 0;

function initPortraitCanvases() {
    p1PortraitCanvas = makeHudCanvas('p1-portrait');
    p2PortraitCanvas = makeHudCanvas('p2-portrait');
    drawPortraitPhoto(p1PortraitCanvas, p1Char, 'idle');
    drawPortraitPhoto(p2PortraitCanvas, p2Char, 'idle');
}

function setPortraitState(player, state) {
    // player: 'p1' or 'p2'
    // state: 'idle' or 'action'
    const isP1 = (player === 'p1');
    const charKey = isP1 ? p1Char : p2Char;
    const canvas = isP1 ? p1PortraitCanvas : p2PortraitCanvas;
    const currentState = isP1 ? p1PortraitState : p2PortraitState;
    if (!canvas || currentState === state) return;

    if (isP1) p1PortraitState = state;
    else p2PortraitState = state;
    drawPortraitPhoto(canvas, charKey, state);

    // Flash the portrait container when hit
    const containerId = isP1 ? 'p1-portrait' : 'p2-portrait';
    const container = document.getElementById(containerId);
    if (container && state === 'action') {
        container.style.boxShadow = isP1 ? '0 0 8px 3px rgba(239,68,68,0.8)' : '0 0 8px 3px rgba(239,68,68,0.8)';
        container.style.borderColor = '#ef4444';
        setTimeout(() => {
            container.style.boxShadow = '';
            container.style.borderColor = '';
        }, 400);
    }
}

function updatePortraits(dt) {
    // P1 portrait cycling (Holyfield-style)
    // Attack: show intense/aggressive expression
    // Hit: show stunned/pain expression (same action img for simplicity)
    if (player1State) {
        if (player1State.attackTimer > 0.1) {
            p1PortraitTimer = 0.7;
            setPortraitState('p1', 'action');
        } else if (player1State.hitstun > 0.05) {
            p1PortraitTimer = 0.6;
            setPortraitState('p1', 'action');
        }
        // Auto-revert
        if (p1PortraitTimer > 0) {
            p1PortraitTimer -= dt;
            if (p1PortraitTimer <= 0) {
                setPortraitState('p1', 'idle');
                // Reset portrait border
                const c = document.getElementById('p1-portrait');
                if (c) { c.style.boxShadow = ''; c.style.borderColor = ''; }
            }
        }
    }

    // P2 portrait cycling
    if (player2State) {
        if (player2State.attackTimer > 0.1) {
            p2PortraitTimer = 0.7;
            setPortraitState('p2', 'action');
        } else if (player2State.hitstun > 0.05) {
            p2PortraitTimer = 0.6;
            setPortraitState('p2', 'action');
        }
        if (p2PortraitTimer > 0) {
            p2PortraitTimer -= dt;
            if (p2PortraitTimer <= 0) {
                setPortraitState('p2', 'idle');
                const c = document.getElementById('p2-portrait');
                if (c) { c.style.boxShadow = ''; c.style.borderColor = ''; }
            }
        }
    }
}

function updateHPUI() {
    if (!player1State || !player2State) return;
    const p1Hp = document.getElementById('p1-hp');
    const p2Hp = document.getElementById('p2-hp');
    const p1Pct = (player1State.health / (player1State.maxHealth||100)) * 100;
    const p2Pct = (player2State.health / (player2State.maxHealth||100)) * 100;
    if (p1Hp) p1Hp.style.width = p1Pct + "%";
    if (p2Hp) p2Hp.style.width = p2Pct + "%";
    setTimeout(() => {
        const p1Slow = document.getElementById('p1-hp-slow');
        const p2Slow = document.getElementById('p2-hp-slow');
        if (p1Slow) p1Slow.style.width = p1Pct + "%";
        if (p2Slow) p2Slow.style.width = p2Pct + "%";
    }, 500);
    const p1S = document.getElementById('p1-super');
    const p2S = document.getElementById('p2-super');
    if (p1S) p1S.style.width = player1State.super + "%";
    if (p2S) p2S.style.width = player2State.super + "%";
}

function triggerCameraShake() {
    if (!threeCamera) return;
    // Use the tracked target position for shake base
    const oX = window._camTargetX || threeCamera.position.x;
    const oZ = window._camTargetZ || threeCamera.position.z;
    const oY = threeCamera.position.y;
    for (let i = 0; i < 8; i++) {
        setTimeout(() => {
            if (threeCamera) {
                threeCamera.position.x = oX + (Math.random()-0.5)*0.18;
                threeCamera.position.y = oY + (Math.random()-0.5)*0.12;
            }
        }, i*25);
    }
    // Restore after shake to target position (camera tracking will re-smooth it)
    setTimeout(() => { if (threeCamera) threeCamera.position.set(oX, oY, oZ); }, 220);
}

// =================== END MATCH ===================
function endMatch(timedOut = false) {
    gameActive = false;
    clearInterval(gameTimerInterval);

    let winnerKey = p1Char;
    let winnerLabel = CHAR_DEFS[p1Char].name;
    let sub = "CAFE DOMINANCE ESTABLISHED!";
    if (timedOut) {
        if (player1State.health < player2State.health) {
            winnerKey = p2Char;
            winnerLabel = CHAR_DEFS[p2Char].name;
            sub = "TIME UP — DEFENDER PREVAILS";
        }
    } else {
        if (player1State.health <= 0) {
            winnerKey = p2Char;
            winnerLabel = CHAR_DEFS[p2Char].name;
            sub = "K.O. SECURED!";
        }
    }
    audio.playVoice("Knock out. " + winnerLabel + " wins!");

    // Knock down loser via Z rotation
    if (p1Mesh && p2Mesh) {
        if (player1State.health <= 0) p1Mesh.rotation.z = Math.PI/2;
        else p2Mesh.rotation.z = -Math.PI/2;
    }

    const wt = document.getElementById('winner-title');
    const ws = document.getElementById('winner-sub');
    if (wt) wt.innerText = winnerLabel + " WINS!";
    if (ws) ws.innerText = sub;
    setTimeout(() => {
        const sc = document.getElementById('game-over-screen');
        if (sc) sc.classList.remove('scale-0','opacity-0');
    }, 1500);
}

function restartMatch() {
    const ps = document.getElementById('pause-screen');
    if (ps) ps.classList.add('hidden');
    gamePaused = false;
    const sc = document.getElementById('game-over-screen');
    if (sc) sc.classList.add('scale-0','opacity-0');
    if (p1Mesh && p2Mesh) {
        p1Mesh.rotation.z = 0;
        p2Mesh.rotation.z = 0;
    }
    if (player1State && player2State) {
        const _mo = (MAP_DEFS[selectedMap] || MAP_DEFS.cafe).phaserOffset;
        player1State.body.setPosition(250 + _mo, 350);
        player2State.body.setPosition(550 + _mo, 350);
        player1State.attackTimer = 0;
        player2State.attackTimer = 0;
        player1State.hitstun = 0;
        player2State.hitstun = 0;
    }
    // BUGFIX: fully reset all breakables, including visual state
    breakables.forEach(b => { if (b.reset) b.reset(); });
    // Clear lingering particles
    while (particles.length > 0) {
        const p = particles.pop();
        threeScene.remove(p.mesh);
        p.geo.dispose(); p.mat.dispose();
    }
    gameActive = true;
    gamePaused = false;
    startMatchSequence();
}

function exitToLobby() {
    const ps = document.getElementById('pause-screen');
    if (ps) ps.classList.add('hidden');
    gamePaused = false;
    const sc = document.getElementById('game-over-screen');
    if (sc) sc.classList.add('scale-0','opacity-0');
    // Tear down Phaser & Three to allow re-init with new chars
    gameActive = false;
    if (gameTimerInterval) clearInterval(gameTimerInterval);
    if (phaserGame) { try { phaserGame.destroy(true); } catch(e){} phaserGame = null; }
    if (threeRenderer) {
        const c = document.getElementById('three-container');
        if (c) c.innerHTML = '';
        threeRenderer = null; threeScene = null; threeCamera = null;
        p1Mesh = null; p2Mesh = null;
        breakables = []; particles = [];
    }
    // Reset portrait tracking
    p1PortraitCanvas = null;
    p2PortraitCanvas = null;
    p1PortraitState = 'idle';
    p2PortraitState = 'idle';
    // Reset camera tracking to selected map center
    window._camTargetX = (MAP_DEFS[selectedMap] || MAP_DEFS.cafe).cx;
    window._camTargetZ = 10;
    const lobby = document.getElementById('lobby-screen');
    if (lobby) {
        lobby.style.display = 'flex';
        setTimeout(() => lobby.classList.remove('opacity-0','pointer-events-none'), 100);
    }
}

// =================== RENDER TICK ===================
function animate() {
    requestAnimationFrame(animate);
    if (!threeClock) return;
    const dt = gamePaused ? 0 : threeClock.getDelta();
    update3DParticles(dt);
    updateVFXSprites(dt);

    // Side-scrolling camera: maintain strict side-profile view,
    // tracking midpoint and zooming out as fighters spread apart
    if (threeCamera && player1State && player2State && p1Mesh && p2Mesh) {
        const midX = (p1Mesh.position.x + p2Mesh.position.x) * 0.5;
        const spread = Math.abs(p1Mesh.position.x - p2Mesh.position.x);
        // targetZ: close when fighters touch (~3 units), far when across stage (~12 units)
        const targetZ = Math.max(7, Math.min(20, 6 + spread * 1.8));
        // Raise camera slightly when far apart so both bodies stay in frame
        const targetY = Math.max(1.0, Math.min(2.2, 0.8 + spread * 0.12));
        window._camTargetX = window._camTargetX || 0;
        window._camTargetZ = window._camTargetZ || 10;
        window._camTargetY = window._camTargetY || 1.2;
        window._camTargetX += (midX - window._camTargetX) * 0.08;
        window._camTargetZ += (targetZ - window._camTargetZ) * 0.05;
        window._camTargetY += (targetY - window._camTargetY) * 0.04;
        threeCamera.position.set(window._camTargetX, window._camTargetY, window._camTargetZ);
        threeCamera.lookAt(window._camTargetX, 0.9, 0);

        // Update zone indicator based on camera X position
        const zoneEl = document.getElementById('zone-indicator');
        if (zoneEl && gameActive) {
            if (midX < 14) zoneEl.innerText = '☕ CAFE';
            else if (midX < 40) zoneEl.innerText = '🏢 OFFICE';
            else zoneEl.innerText = '🚗 PARKING';
        }
    }

    if (threeRenderer && threeScene && threeCamera) {
        threeRenderer.render(threeScene, threeCamera);
    }
}

